#include <iostream>
#include <fstream>
#include <vector>
#include <string>
#include "cJSON.h"
#include "lodepng.h"

using namespace std;

int main(int argc, char** argv) {
    if (argc < 3) {
        return 1;
    }
    const char* weights_file = argv[1];
    const char* image_file = argv[2];

    FILE* f = fopen(weights_file, "r");
    if(!f) return 1;
    fseek(f, 0, SEEK_END);
    long fsize = ftell(f);
    fseek(f, 0, SEEK_SET);
    char* json_data = (char*)malloc(fsize + 1);
    fread(json_data, 1, fsize, f);
    fclose(f);
    json_data[fsize] = 0;

    cJSON* root = cJSON_Parse(json_data);
    free(json_data);
    if(!root) return 1;

    auto get_matrix = [&](const char* name, vector<vector<float>>& mat) {
        cJSON* arr = cJSON_GetObjectItem(root, name);
        if (!arr) return;
        int rows = cJSON_GetArraySize(arr);
        mat.resize(rows);
        for(int i=0; i<rows; i++) {
            cJSON* row = cJSON_GetArrayItem(arr, i);
            int cols = cJSON_GetArraySize(row);
            mat[i].resize(cols);
            for(int j=0; j<cols; j++) {
                mat[i][j] = cJSON_GetArrayItem(row, j)->valuedouble;
            }
        }
    };

    auto get_vector = [&](const char* name, vector<float>& vec) {
        cJSON* arr = cJSON_GetObjectItem(root, name);
        if (!arr) return;
        int size = cJSON_GetArraySize(arr);
        vec.resize(size);
        for(int i=0; i<size; i++) {
            vec[i] = cJSON_GetArrayItem(arr, i)->valuedouble;
        }
    };

    vector<vector<float>> W1, W2, W3;
    vector<float> b1, b2, b3;

    get_matrix("input_layer.weight", W1);
    get_vector("input_layer.bias", b1);
    get_matrix("hidden_layer.weight", W2);
    get_vector("hidden_layer.bias", b2);
    get_matrix("output_layer.weight", W3);
    get_vector("output_layer.bias", b3);

    cJSON_Delete(root);

    unsigned char* image = 0;
    unsigned width, height;
    unsigned error = lodepng_decode_file(&image, &width, &height, image_file, LCT_GREY, 8);
    if(error) return 1;

    vector<float> x(width * height);
    for(size_t i=0; i<x.size(); i++) {
        x[i] = image[i] / 255.0f;
    }
    free(image);

    auto linear_relu = [&](const vector<vector<float>>& W, const vector<float>& b, const vector<float>& in, vector<float>& out, bool relu) {
        int out_dim = W.size();
        if (out_dim == 0) return;
        int in_dim = W[0].size();
        out.resize(out_dim);
        for(int i=0; i<out_dim; i++) {
            float sum = b[i];
            for(int j=0; j<in_dim; j++) {
                sum += W[i][j] * in[j];
            }
            if (relu) {
                out[i] = sum > 0 ? sum : 0;
            } else {
                out[i] = sum;
            }
        }
    };

    vector<float> layer1, layer2, layer3;
    linear_relu(W1, b1, x, layer1, true);
    linear_relu(W2, b2, layer1, layer2, true);
    linear_relu(W3, b3, layer2, layer3, false);

    int best_class = 0;
    float best_val = layer3.empty() ? 0 : layer3[0];
    for(size_t i=1; i<layer3.size(); i++) {
        if(layer3[i] > best_val) {
            best_val = layer3[i];
            best_class = i;
        }
    }

    printf("%d", best_class);

    return 0;
}
